@page "/board"
@using sv_d4939c51d73b4dab99e0d5f4d0199bc5
@inject ITaskService TaskService
@rendermode InteractiveServer

<PageTitle>Kanban Board</PageTitle>

<h2 class="mb-3">Project Board</h2>

@if (_loading)
{
    <div class="d-flex justify-content-center my-5">
        <div class="spinner-border" role="status">
            <span class="visually-hidden">Loading…</span>
        </div>
    </div>
}
else if (_error is not null)
{
    <div class="alert alert-danger" role="alert">
        <strong>Error:</strong> @_error
    </div>
}
else
{
    <!-- Summary Stats Bar -->
    <div class="row g-2 mb-3">
        <div class="col"><div class="card text-center p-2"><strong>Total</strong><br />@_allTasks.Count</div></div>
        @foreach (var col in Columns)
        {
            <div class="col">
                <div class="card text-center p-2"><strong>@col</strong><br />@TasksInColumn(col).Count</div>
            </div>
        }
        <div class="col"><div class="card text-center p-2 text-danger"><strong>Overdue</strong><br />@_allTasks.Count(t => t.DueDate.Date < DateTime.Today)</div></div>
    </div>

    <!-- Search Bar -->
    <div class="mb-3">
        <input type="text" class="form-control" placeholder="Search tasks by title…"
               @bind="_searchText" @bind:event="oninput" />
    </div>

    <!-- Kanban Columns -->
    <div class="row g-3">
        @for (var i = 0; i < Columns.Length; i++)
        {
            var colIndex = i;
            var colName = Columns[colIndex];
            var colTasks = FilteredTasksInColumn(colName);

            <div class="col-md-4">
                <div class="card">
                    <div class="card-header d-flex justify-content-between align-items-center">
                        <strong>@colName</strong>
                        <span class="badge bg-secondary">@colTasks.Count</span>
                    </div>
                    <div class="card-body p-2" style="min-height:200px;">
                        @foreach (var task in colTasks)
                        {
                            <div class="card mb-2">
                                <div class="card-body p-2">
                                    <h6 class="card-title mb-1">@task.Title</h6>
                                    <p class="mb-1 text-muted small">@task.Assignee</p>
                                    <span class="badge @PriorityClass(task.Priority) me-1">@task.Priority</span>
                                    <small class="text-muted">@task.DueDate.ToString("MMM dd")</small>
                                    <div class="mt-2 d-flex gap-1">
                                        @if (colIndex > 0)
                                        {
                                            <button class="btn btn-outline-secondary btn-sm"
                                                    @onclick="() => MoveTaskAsync(task.Id, Columns[colIndex - 1])">
                                                ← Move Left
                                            </button>
                                        }
                                        @if (colIndex < Columns.Length - 1)
                                        {
                                            <button class="btn btn-outline-secondary btn-sm"
                                                    @onclick="() => MoveTaskAsync(task.Id, Columns[colIndex + 1])">
                                                Move Right →
                                            </button>
                                        }
                                    </div>
                                </div>
                            </div>
                        }

                        <!-- Inline Add Task Form -->
                        @if (_addingColumn == colName)
                        {
                            <div class="card border-primary mt-2">
                                <div class="card-body p-2">
                                    <input type="text" class="form-control form-control-sm mb-1"
                                           placeholder="Title" @bind="_newTitle" />
                                    <input type="text" class="form-control form-control-sm mb-1"
                                           placeholder="Assignee" @bind="_newAssignee" />
                                    <select class="form-select form-select-sm mb-1" @bind="_newPriority">
                                        <option value="High">High</option>
                                        <option value="Medium">Medium</option>
                                        <option value="Low">Low</option>
                                    </select>
                                    <input type="date" class="form-control form-control-sm mb-2"
                                           @bind="_newDueDate" />
                                    <div class="d-flex gap-1">
                                        <button class="btn btn-primary btn-sm" @onclick="SaveNewTaskAsync">Save</button>
                                        <button class="btn btn-secondary btn-sm" @onclick="CancelAdd">Cancel</button>
                                    </div>
                                </div>
                            </div>
                        }
                        else
                        {
                            <button class="btn btn-outline-primary btn-sm w-100 mt-1"
                                    @onclick="() => StartAdd(colName)">
                                + Add Task
                            </button>
                        }
                    </div>
                </div>
            </div>
        }
    </div>
}

@code {
    private static readonly string[] Columns = ["To Do", "In Progress", "Done"];

    private List<TaskItem> _allTasks = new();
    private bool _loading = true;
    private string? _error;
    private string _searchText = string.Empty;

    // Add-task form state
    private string? _addingColumn;
    private string _newTitle = string.Empty;
    private string _newAssignee = string.Empty;
    private string _newPriority = "Medium";
    private DateTime _newDueDate = DateTime.Today.AddDays(7);

    protected override async Task OnInitializedAsync()
    {
        try
        {
            _allTasks = await TaskService.GetAllTasksAsync();
        }
        catch (Exception ex)
        {
            _error = ex.Message;
        }
        finally
        {
            _loading = false;
        }
    }

    private List<TaskItem> TasksInColumn(string status) =>
        _allTasks.Where(t => t.Status == status).ToList();

    private List<TaskItem> FilteredTasksInColumn(string status) =>
        _allTasks
            .Where(t => t.Status == status &&
                        (string.IsNullOrWhiteSpace(_searchText) ||
                         t.Title.Contains(_searchText, StringComparison.OrdinalIgnoreCase)))
            .ToList();

    private static string PriorityClass(string priority) => priority switch
    {
        "High" => "bg-danger",
        "Medium" => "bg-warning text-dark",
        "Low" => "bg-success",
        _ => "bg-secondary"
    };

    private async Task MoveTaskAsync(int taskId, string newStatus)
    {
        try
        {
            await TaskService.UpdateTaskStatusAsync(taskId, newStatus);
            var idx = _allTasks.FindIndex(t => t.Id == taskId);
            if (idx >= 0)
            {
                var old = _allTasks[idx];
                _allTasks[idx] = old with { Status = newStatus };
            }
        }
        catch (Exception ex)
        {
            _error = ex.Message;
        }
    }

    private void StartAdd(string column)
    {
        _addingColumn = column;
        _newTitle = string.Empty;
        _newAssignee = string.Empty;
        _newPriority = "Medium";
        _newDueDate = DateTime.Today.AddDays(7);
    }

    private void CancelAdd() => _addingColumn = null;

    private async Task SaveNewTaskAsync()
    {
        if (string.IsNullOrWhiteSpace(_newTitle) || _addingColumn is null)
            return;

        try
        {
            var created = await TaskService.CreateTaskAsync(_newTitle, _newAssignee, _newPriority, _newDueDate);
            // CreateTaskAsync returns the task with its default status; update to the target column if different.
            if (created.Status != _addingColumn)
            {
                await TaskService.UpdateTaskStatusAsync(created.Id, _addingColumn);
                created = created with { Status = _addingColumn };
            }
            _allTasks.Add(created);
            _addingColumn = null;
        }
        catch (Exception ex)
        {
            _error = ex.Message;
        }
    }
}

